package com.sts.sinorita.repository;

import com.sts.sinorita.entity.AcctItemType;
import com.sts.sinorita.projection.QryBalanceTypeProjection;
import com.sts.sinorita.projection.acct.AcctItemTypeAscProjection;
import com.sts.sinorita.projection.acct.AcctItemTypeDetailProjection;
import com.sts.sinorita.projection.acct.AcctItemTypeProjection;

import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.query.Param;
import org.springframework.stereotype.Repository;
import java.util.List;
import java.util.Optional;

@Repository
public interface AcctItemTypeRepository extends JpaRepository<AcctItemType, Integer> {
  boolean existsByAcctItemTypeNameIgnoreCase(String acctItemTypeName);
  boolean existsByAcctItemTypeNameIgnoreCaseAndIdNot(String acctItemTypeName, Integer acctItemTypeId);
  boolean existsByExchangeItemTypeId(Integer exchangeItemTypeId);
  boolean existsByParentId(Integer parentId);

  @Query(value = "SELECT ACCT_ITEM_TYPE_ID AS id, ACCT_ITEM_TYPE_NAME AS acctItemTypeName FROM ACCT_ITEM_TYPE WHERE (:acctItemTypeName IS NULL OR LOWER(ACCT_ITEM_TYPE_NAME) LIKE LOWER(CONCAT('%', :acctItemTypeName, '%'))) ORDER BY ACCT_ITEM_TYPE_NAME ASC", nativeQuery = true)
  Page<AcctItemTypeAscProjection> findNameAcctItemType(Pageable pageable, @Param("acctItemTypeName") String acctItemTypeName);

  @Query(value = "SELECT 1 FROM ACCT_ITEM_TYPE ait WHERE ait.ACCT_RES_ID = :acctResId FETCH FIRST 1 ROWS ONLY", nativeQuery = true)
  Optional<Integer> isReferencedInAcctRes(@Param("acctResId") Long acctResId);

  @Query(value = "SELECT ait.ACCT_ITEM_TYPE_NAME, ar.ACCT_RES_NAME, bt.BAL_TYPE_NAME FROM ACCT_ITEM_TYPE ait JOIN ACCT_RES ar ON ait.ACCT_RES_ID = ar.ACCT_RES_ID JOIN BAL_TYPE bt ON ar.BAL_TYPE = bt.BAL_TYPE ORDER BY ait.ACCT_ITEM_TYPE_NAME asc ", nativeQuery = true)
  List<Object[]> findAcctItemTypeList();

  @Query(value = "SELECT A.ACCT_ITEM_TYPE_ID AS acctItemTypeId, A.ACCT_RES_ID AS acctResId, A.PARENT_ID AS parentId, A.EXCHANGE_ITEM_TYPE_ID AS exchangeItemTypeId, A.ACCT_ITEM_TYPE_NAME AS acctItemTypeName, A.COMMENTS AS comments, A.ACCT_ITEM_TYPE_CODE AS acctItemTypeCode, A.USAGE_TYPE AS usageType, A.GST_TYPE AS gstType, A.FEE_TYPE AS feeType, A.ZERO_FEE_PRINT_FLAG AS zeroFeePrintFlag, A.BILL_PRIORITY AS billPriority, A.ACCT_ITEM_GROUP_ID AS acctItemGroupId, A.DEFAULT_TAX_ITEM_TYPE_ID AS defaultTaxItemTypeId, B.ACCT_RES_NAME AS acctResName, C.BAL_TYPE AS balType, B.IS_CURRENCY AS isCurrency, B.CREDIT_LIMIT AS creditLimit, C.BAL_TYPE_NAME AS balTypeName, M.BIND_ACCT_ITEM_TYPE_ID AS taxAcctItemTypeId, N.BIND_ACCT_ITEM_TYPE_ID AS discountAcctItemTypeId, D.TAX_APPLY_ID AS taxApplyId,( SELECT COUNT(1) FROM ACCT_ITEM_TYPE T WHERE T.PARENT_ID = A.ACCT_ITEM_TYPE_ID) AS child FROM ACCT_ITEM_TYPE A JOIN ACCT_RES B ON A.ACCT_RES_ID = B.ACCT_RES_ID JOIN BAL_TYPE C ON B.BAL_TYPE = C.BAL_TYPE LEFT JOIN ACCT_ITEM_TYPE_BIND M ON A.ACCT_ITEM_TYPE_ID = M.ACCT_ITEM_TYPE_ID AND M.ACCT_ITEM_TYPE_BIND_TYPE = 'T' LEFT JOIN ACCT_ITEM_TYPE_BIND N ON A.ACCT_ITEM_TYPE_ID = N.ACCT_ITEM_TYPE_ID AND N.ACCT_ITEM_TYPE_BIND_TYPE = 'D' LEFT JOIN ACCT_ITEM_TAX_APPLY D ON A.ACCT_ITEM_TYPE_ID = D.ACCT_ITEM_TYPE_ID WHERE A.PARENT_ID IS NULL AND (:spId IS NULL OR NVL(A.SP_ID, 0) = :spId) AND (:acctResId IS NULL OR A.ACCT_RES_ID = :acctResId) ORDER BY A.ACCT_ITEM_TYPE_NAME", countQuery = "SELECT COUNT(*) FROM ACCT_ITEM_TYPE A WHERE A.PARENT_ID IS NULL AND(:spId IS NULL OR NVL(A.SP_ID, 0) = :spId) AND (:acctResId IS NULL OR A.ACCT_RES_ID = :acctResId)", nativeQuery = true)
  Page<AcctItemTypeProjection> getAcctItemTypeQueryList(@Param("spId") Integer spId, @Param("acctResId") Integer acctResId, Pageable pageable);

  @Query(value = "SELECT A.ACCT_ITEM_TYPE_ID AS acctItemTypeId, A.ACCT_RES_ID AS acctResId, A.PARENT_ID AS parentId, A.EXCHANGE_ITEM_TYPE_ID AS exchangeItemTypeId, A.ACCT_ITEM_TYPE_NAME AS acctItemTypeName, A.COMMENTS AS comments, A.ACCT_ITEM_TYPE_CODE AS acctItemTypeCode, A.USAGE_TYPE AS usageType, A.GST_TYPE AS gstType, A.FEE_TYPE AS feeType, A.FEE_CLASS AS feeClass, A.ZERO_FEE_PRINT_FLAG AS zeroFeePrintFlag, A.BILL_PRIORITY AS billPriority, A.ACCT_ITEM_GROUP_ID AS acctItemGroupId, A.DEFAULT_TAX_ITEM_TYPE_ID AS defaultTaxItemTypeId, B.ACCT_RES_NAME AS acctResName, C.BAL_TYPE AS balType, B.IS_CURRENCY AS isCurrency, B.CREDIT_LIMIT AS creditLimit, C.BAL_TYPE_NAME AS balTypeName, M.BIND_ACCT_ITEM_TYPE_ID AS taxAcctItemTypeId, N.BIND_ACCT_ITEM_TYPE_ID AS discountAcctItemTypeId, D.TAX_APPLY_ID AS taxApplyId FROM ACCT_ITEM_TYPE A JOIN ACCT_RES B ON A.ACCT_RES_ID = B.ACCT_RES_ID JOIN BAL_TYPE C ON B.BAL_TYPE = C.BAL_TYPE LEFT JOIN ACCT_ITEM_TAX_APPLY D ON A.ACCT_ITEM_TYPE_ID = D.ACCT_ITEM_TYPE_ID LEFT JOIN( SELECT D.ACCT_ITEM_TYPE_ID, D.BIND_ACCT_ITEM_TYPE_ID FROM ACCT_ITEM_TYPE_BIND D WHERE D.ACCT_ITEM_TYPE_BIND_TYPE = 'T') M ON A.ACCT_ITEM_TYPE_ID = M.ACCT_ITEM_TYPE_ID LEFT JOIN ( SELECT E.ACCT_ITEM_TYPE_ID, E.BIND_ACCT_ITEM_TYPE_ID FROM ACCT_ITEM_TYPE_BIND E WHERE E.ACCT_ITEM_TYPE_BIND_TYPE = 'D' ) N ON A.ACCT_ITEM_TYPE_ID = N.ACCT_ITEM_TYPE_ID WHERE A.ACCT_ITEM_TYPE_ID = NVL(:acctItemTypeId, A.ACCT_ITEM_TYPE_ID) AND B.ACCT_RES_ID = NVL(:acctResId, B.ACCT_RES_ID) AND (:nullFlag IS NULL OR (:nullFlag = 1 AND A.PARENT_ID IS NULL)) AND (:parentId IS NULL OR A.PARENT_ID = :parentId) AND (:priceVerId IS NULL OR A.ACCT_ITEM_TYPE_ID IN ( SELECT C.ACCT_ITEM_TYPE_ID FROM PRICE C WHERE C.PRICE_VER_ID = :priceVerId )) AND (:priceVerIdExists IS NULL OR B.ACCT_RES_ID NOT IN ( SELECT D.ACCT_RES_ID FROM PRICE C, ACCT_ITEM_TYPE D WHERE C.ACCT_ITEM_TYPE_ID = D.ACCT_ITEM_TYPE_ID AND C.PRICE_VER_ID = :priceVerIdExists )) AND (:priceVerIdEx IS NULL OR :curPriceId IS NULL OR B.ACCT_RES_ID NOT IN ( SELECT D.ACCT_RES_ID FROM PRICE C, ACCT_ITEM_TYPE D WHERE C.ACCT_ITEM_TYPE_ID = D.ACCT_ITEM_TYPE_ID AND C.PRICE_VER_ID = :priceVerIdEx AND C.PRICE_ID <> :curPriceId )) AND NVL(A.SP_ID, 0) = NVL(:spId, NVL(A.SP_ID, 0)) AND (:usageType IS NULL OR A.USAGE_TYPE = :usageType) AND (:defaultAcctResId IS NULL OR B.ACCT_RES_ID = :defaultAcctResId) AND (:acctItemTypeName IS NULL OR UPPER(A.ACCT_ITEM_TYPE_NAME) LIKE '%' || UPPER(:acctItemTypeName) || '%') ORDER BY A.ACCT_ITEM_TYPE_NAME", nativeQuery = true)
  Page<AcctItemTypeDetailProjection> getAcctItemTypeDetailsForAdd(@Param("acctItemTypeId") Integer acctItemTypeId, @Param("acctResId") Integer acctResId, @Param("nullFlag") Integer nullFlag, @Param("parentId") Integer parentId, @Param("priceVerId") Integer priceVerId, @Param("priceVerIdExists") Integer priceVerIdExists, @Param("priceVerIdEx") Integer priceVerIdEx, @Param("curPriceId") Integer curPriceId, @Param("spId") Integer spId, @Param("usageType") String usageType, @Param("defaultAcctResId") Integer defaultAcctResId, @Param("acctItemTypeName") String acctItemTypeName, Pageable pageable);

  @Query(value = "SELECT A.BAL_TYPE, A.BAL_TYPE_NAME, B.ACCT_RES_ID, B.ACCT_RES_NAME, B.IS_CURRENCY, B.COMMENTS, B.CREDIT_LIMIT, B.MAX_VALUE, B.REFILLABLE, B.STD_CODE, B.PAYMENT_FORCE, B.PARENT_ACCT_RES_ID, B.IS_FREE_UNIT, B.DEFAULT_ACCT_ITEM_TYPE_ID, C.ACCT_RES_NAME AS PARENT_ACCT_RES_NAME, D.ACCT_ITEM_TYPE_NAME, B.UNIT_TYPE_ID, B.UNIT_PRECISION, E.UNIT_TYPE_NAME, B.RATIO_MONEY, B.RATIO_PRECISION, B.PRIORITY, CASE WHEN B.EXTEND_RULE = '000000' THEN '' ELSE B.EXTEND_RULE END AS EXTEND_RULE, CASE WHEN B.EXTEND_RULE = '210000' THEN 'Best Rule' WHEN B.EXTEND_RULE = '100000' THEN 'Accumulation Rule' ELSE '' END AS EXTEND_RULE_NAME, B.MAX_ADJUST_VALUE, B.MAX_CHG_VALUE, B.MAX_EXP_DATE, B.RESET_ZERO, B.GRACE_PERIOD, B.MAX_ROLLOVER, F.DAY_THRESHOLD, F.WEEK_THRESHOLD, F.MONTH_THRESHOLD, F.DAY_COUNT, F.WEEK_COUNT, F.MONTH_COUNT, F.MIN_RESIDUAL_BAL, F.MAX_ALLOWED, F.MIN_ALLOWED, F.TRANSFER_FACTOR, CASE WHEN B.RESET_ZERO = 'Y' THEN 'Clear bal after expired' ELSE 'Can not clear bal after expired' END AS RESET_ZERO_NAME FROM BAL_TYPE A JOIN ACCT_RES B ON A.BAL_TYPE = B.BAL_TYPE LEFT JOIN ACCT_RES C ON B.PARENT_ACCT_RES_ID = C.ACCT_RES_ID LEFT JOIN ACCT_ITEM_TYPE D ON B.DEFAULT_ACCT_ITEM_TYPE_ID = D.ACCT_ITEM_TYPE_ID LEFT JOIN UNIT_TYPE E ON B.UNIT_TYPE_ID = E.UNIT_TYPE_ID LEFT JOIN TRANS_ACCT_RES_CFG F ON B.ACCT_RES_ID = F.ACCT_RES_ID WHERE 1 = 1 AND (:acctItemTypeName IS NULL OR LOWER(D.ACCT_ITEM_TYPE_NAME) LIKE LOWER('%' || :acctItemTypeName || '%')) AND (:acctResId IS NULL OR B.ACCT_RES_ID = :acctResId) AND (:balType IS NULL OR A.BAL_TYPE = :balType) AND (:spId IS NULL OR NVL(B.SP_ID, 0) = :spId) AND ( :exceptBalTypes IS NULL OR A.BAL_TYPE NOT IN (:exceptBalTypes)) AND ( :spId IS NULL OR TO_CHAR(B.ACCT_RES_ID) IN ( SELECT NVL(PARAM_VALUE, DEFAULT_VALUE) FROM CONFIG_ITEM_PARAM WHERE PARAM_CODE = 'DEFAULT_ACCT_RES_ID' ) OR NVL(B.SP_ID, 0) = :spId ) ORDER BY A.BAL_TYPE, B.ACCT_RES_ID", countQuery = "SELECT A.BAL_TYPE, A.BAL_TYPE_NAME, B.ACCT_RES_ID, B.ACCT_RES_NAME, B.IS_CURRENCY, B.COMMENTS, B.CREDIT_LIMIT, B.MAX_VALUE, B.REFILLABLE, B.STD_CODE, B.PAYMENT_FORCE, B.PARENT_ACCT_RES_ID, B.IS_FREE_UNIT, B.DEFAULT_ACCT_ITEM_TYPE_ID, C.ACCT_RES_NAME AS PARENT_ACCT_RES_NAME, D.ACCT_ITEM_TYPE_NAME, B.UNIT_TYPE_ID, B.UNIT_PRECISION, E.UNIT_TYPE_NAME, B.RATIO_MONEY, B.RATIO_PRECISION, B.PRIORITY, CASE WHEN B.EXTEND_RULE = '000000' THEN '' ELSE B.EXTEND_RULE END AS EXTEND_RULE, CASE WHEN B.EXTEND_RULE = '210000' THEN 'Best Rule' WHEN B.EXTEND_RULE = '100000' THEN 'Accumulation Rule' ELSE '' END AS EXTEND_RULE_NAME, B.MAX_ADJUST_VALUE, B.MAX_CHG_VALUE, B.MAX_EXP_DATE, B.RESET_ZERO, B.GRACE_PERIOD, B.MAX_ROLLOVER, F.DAY_THRESHOLD, F.WEEK_THRESHOLD, F.MONTH_THRESHOLD, F.DAY_COUNT, F.WEEK_COUNT, F.MONTH_COUNT, F.MIN_RESIDUAL_BAL, F.MAX_ALLOWED, F.MIN_ALLOWED, F.TRANSFER_FACTOR, CASE WHEN B.RESET_ZERO = 'Y' THEN 'Clear bal after expired' ELSE 'Can not clear bal after expired' END AS RESET_ZERO_NAME FROM BAL_TYPE A JOIN ACCT_RES B ON A.BAL_TYPE = B.BAL_TYPE LEFT JOIN ACCT_RES C ON B.PARENT_ACCT_RES_ID = C.ACCT_RES_ID LEFT JOIN ACCT_ITEM_TYPE D ON B.DEFAULT_ACCT_ITEM_TYPE_ID = D.ACCT_ITEM_TYPE_ID LEFT JOIN UNIT_TYPE E ON B.UNIT_TYPE_ID = E.UNIT_TYPE_ID LEFT JOIN TRANS_ACCT_RES_CFG F ON B.ACCT_RES_ID = F.ACCT_RES_ID WHERE 1 = 1 AND (:acctItemTypeName IS NULL OR LOWER(D.ACCT_ITEM_TYPE_NAME) LIKE LOWER('%' || :acctItemTypeName || '%')) AND (:acctResId IS NULL OR B.ACCT_RES_ID = :acctResId) AND (:balType IS NULL OR A.BAL_TYPE = :balType) AND (:spId IS NULL OR NVL(B.SP_ID, 0) = :spId) AND ( :exceptBalTypes IS NULL OR A.BAL_TYPE NOT IN (:exceptBalTypes)) AND ( :spId IS NULL OR TO_CHAR(B.ACCT_RES_ID) IN ( SELECT NVL(PARAM_VALUE, DEFAULT_VALUE) FROM CONFIG_ITEM_PARAM WHERE PARAM_CODE = 'DEFAULT_ACCT_RES_ID' ) OR NVL(B.SP_ID, 0) = :spId ) ORDER BY A.BAL_TYPE, B.ACCT_RES_ID", nativeQuery = true)
  Page<QryBalanceTypeProjection> qryBalanceType(@Param("acctItemTypeName") String acctItemTypeName,  @Param("acctResId") Long acctResId, @Param("balType") String balType, @Param("exceptBalTypes") List<String> exceptBalTypes, @Param("spId") Long spId, Pageable pageable);

    @Query(value = " SELECT ACCT_ITEM_TYPE_ID AS acctItemTypeId, ACCT_RES_ID AS acctResId, PARENT_ID AS parentId, EXCHANGE_ITEM_TYPE_ID AS exchangeItemTypeId, ACCT_ITEM_TYPE_NAME AS acctItemTypeName, COMMENTS AS comments, ACCT_ITEM_TYPE_CODE AS acctItemTypeCode, USAGE_TYPE AS usageType, SP_ID AS spId, GST_TYPE AS gstType, FEE_TYPE AS feeType, FEE_CLASS AS feeClass FROM ACCT_ITEM_TYPE WHERE ACCT_ITEM_TYPE_CODE = :acctItemTypeCode ", nativeQuery = true)
    Optional<AcctItemTypeProjection> selectAcctItemTypeByCode(@Param("acctItemTypeCode") String acctItemTypeCode);
}
